sys_ui_action.script:
(function executeAction(current, previous) {

    // Prevent duplicate Production Changes (optional)
    var existing = new GlideRecord('change_request');
    existing.addQuery('u_change_requests', current.sys_id); // Replace if you use another 
    existing.query();

    if (existing.hasNext()) {
        gs.addErrorMessage('A Production Change already exists for this Change Request.');
        action.setRedirectURL(current);
        return;
    }

    // Create Production Change
    var prodCR = new GlideRecord('change_request');
    prodCR.initialize();

    // Standard fields
    prodCR.type = 'production'; // Use your appropriate change type
    prodCR.assignment_group = current.assignment_group;
	prodCR.short_description = "Production Deployment for" + current.number;
	prodCR.state = 'New';
	prodCR.setValue('chg_model','bb9ac51f93e907d067fef3e43603d697');
    prodCR.u_change_requests = current.sys_id;



    var changeSysId = prodCR.insert();

    if (changeSysId) {

        gs.addInfoMessage(
            'Production Change ' +
            prodCR.number +
            ' has been created successfully.'
        );

        action.setRedirectURL(prodCR);

    } else {

        gs.addErrorMessage('Unable to create the Production Change.');
        action.setRedirectURL(current);

    }

})(current, previous);
